using Standard;namespace BgControls.Windows.Input.Touch;/// <summary>/// 触控管理器，负责全局触控配置、手势事件路由及触控状态管理./// </summary>public static class TouchManager{    /// <summary>    /// 提供 UI 触控相关的辅助功能类.    /// </summary>    internal static class FreeUIHelper    {        /// <summary>        /// 记录已挂起的触控 ID 集合.        /// </summary>        private static HashSet<int> touchIdsSet = new HashSet<int>();        /// <summary>        /// 判断指定的触控 ID 是否处于挂起状态.        /// </summary>        /// <param name="touchId">触控 ID.</param>        /// <returns>如果已挂起则返回 true; 否则返回 false.</returns>        internal static bool IsTouchIdSuspended(int touchId)        {            return TouchManager.FreeUIHelper.touchIdsSet.Contains(touchId);        }        /// <summary>        /// 挂起指定的触控 ID，并在异步回调后移除.        /// </summary>        /// <param name="touchId">触控 ID.</param>        /// <param name="dispatcher">调度器对象.</param>        /// <param name="suspendEndedAction">挂起结束后的回调动作.</param>        internal static void SuspendTouchId(int touchId, Dispatcher dispatcher, Action? suspendEndedAction = null)        {            // 如果 ID 已存在于集合中，则不再处理.            if (!TouchManager.FreeUIHelper.touchIdsSet.Add(touchId))            {                return;            }            // 执行异步调度任务.            TouchManager.FreeUIHelper.DispatchBeginInvoke(dispatcher, () =>            {                // 从挂起集合中移除该 ID.                TouchManager.FreeUIHelper.touchIdsSet.Remove(touchId);                // 执行结束后的逻辑.                if (suspendEndedAction != null)                {                    suspendEndedAction.Invoke();                }            });        }        /// <summary>        /// 在指定的调度器上异步执行动作.        /// </summary>        /// <param name="dispatcher">指定的调度器.</param>        /// <param name="action">待执行的动作.</param>        internal static void DispatchBeginInvoke(Dispatcher dispatcher, Action action)        {            ArgumentNullException.ThrowIfNull(action, nameof(action));            Dispatcher targetDispatcher = dispatcher;            System.Windows.Application currentApp = System.Windows.Application.Current;            // 如果传入的调度器为空，尝试使用全局应用程序的调度器.            if (targetDispatcher == null && currentApp != null)            {                targetDispatcher = currentApp.Dispatcher;            }            // 如果调度器可用且未处于关闭状态，则进行异步推送.            if (targetDispatcher != null && !targetDispatcher.HasShutdownStarted)            {                targetDispatcher.BeginInvoke(action, DispatcherPriority.Input);            }            else            {                // 降级处理：直接同步执行.                action.Invoke();            }        }    }    /// <summary>    /// 拖拽启动触发器的附加属性.    /// </summary>    public static readonly DependencyProperty DragStartTriggerProperty = DependencyProperty.RegisterAttached("DragStartTrigger", typeof(TouchDragStartTrigger), typeof(TouchManager), new PropertyMetadata(TouchManager.DragStartTriggerChanged));    /// <summary>    /// 滚动视图滑动模式的附加属性.    /// </summary>    public static readonly DependencyProperty ScrollViewerSwipeModeProperty = DependencyProperty.RegisterAttached("ScrollViewerSwipeMode", typeof(ScrollViewerSwipeMode), typeof(TouchManager), new PropertyMetadata(TouchManager.ScrollViewerSwipeModeChanged));    /// <summary>    /// 是否挂起鼠标提升的附加属性.    /// </summary>    public static readonly DependencyProperty ShouldSuspendMousePromotionProperty = DependencyProperty.RegisterAttached("ShouldSuspendMousePromotion", typeof(bool), typeof(TouchManager), new PropertyMetadata(TouchManager.ShouldSuspendMousePromotionChanged));    /// <summary>    /// 触控模式的附加属性.    /// </summary>    public static readonly DependencyProperty TouchModeProperty = DependencyProperty.RegisterAttached("TouchMode", typeof(TouchMode), typeof(TouchManager), new FrameworkPropertyMetadata(TouchManager.TouchModeChanged));    /// <summary>    /// 触控命中测试可见性的附加属性（已过时）.    /// </summary>    [Obsolete("Obsoleted with 2016 Q1. Use TouchMode instead.", false)]    public static readonly DependencyProperty IsTouchHitTestVisibleProperty = DependencyProperty.RegisterAttached("IsTouchHitTestVisible", typeof(bool), typeof(TouchManager), new FrameworkPropertyMetadata(true, FrameworkPropertyMetadataOptions.Inherits, TouchManager.IsTouchHitTestVisibleChanged));    private static readonly DependencyProperty ActualIsTouchHitTestVisibleProperty = DependencyProperty.RegisterAttached("ActualIsTouchHitTestVisible", typeof(bool), typeof(TouchManager), new FrameworkPropertyMetadata(true, FrameworkPropertyMetadataOptions.Inherits, TouchManager.ActualIsTouchHitTestVisibleChanged));    private static readonly DependencyProperty ActualShouldSuppressTouchProperty = DependencyProperty.RegisterAttached("ActualShouldSuppressTouch", typeof(bool), typeof(TouchManager), new FrameworkPropertyMetadata(false, FrameworkPropertyMetadataOptions.Inherits, TouchManager.ActualShouldSuppressTouchChanged));    private static readonly DependencyProperty TouchHelperProperty = DependencyProperty.RegisterAttached("TouchHelper", typeof(TouchHelper), typeof(TouchManager), new PropertyMetadata(null));    private static readonly RoutedEvent DragStartedEvent = EventManager.RegisterRoutedEvent("DragStarted", RoutingStrategy.Direct, typeof(TouchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent DragEvent = EventManager.RegisterRoutedEvent("Drag", RoutingStrategy.Direct, typeof(TouchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent DragFinishedEvent = EventManager.RegisterRoutedEvent("DragFinished", RoutingStrategy.Direct, typeof(TouchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent PinchStartedEvent = EventManager.RegisterRoutedEvent("PinchStarted", RoutingStrategy.Direct, typeof(PinchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent PinchEvent = EventManager.RegisterRoutedEvent("Pinch", RoutingStrategy.Direct, typeof(PinchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent PinchFinishedEvent = EventManager.RegisterRoutedEvent("PinchFinished", RoutingStrategy.Direct, typeof(PinchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent SwipeStartedEvent = EventManager.RegisterRoutedEvent("SwipeStarted", RoutingStrategy.Direct, typeof(TouchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent SwipeEvent = EventManager.RegisterRoutedEvent("Swipe", RoutingStrategy.Direct, typeof(SwipeEventHandler), typeof(TouchManager));    private static readonly RoutedEvent SwipeFinishedEvent = EventManager.RegisterRoutedEvent("SwipeFinished", RoutingStrategy.Direct, typeof(TouchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent SwipeInertiaStartedEvent = EventManager.RegisterRoutedEvent("SwipeInertiaStarted", RoutingStrategy.Direct, typeof(RoutedEventHandler), typeof(TouchManager));    private static readonly RoutedEvent SwipeInertiaEvent = EventManager.RegisterRoutedEvent("SwipeInertia", RoutingStrategy.Direct, typeof(SwipeInertiaEventHandler), typeof(TouchManager));    private static readonly RoutedEvent SwipeInertiaFinishedEvent = EventManager.RegisterRoutedEvent("SwipeInertiaFinished", RoutingStrategy.Direct, typeof(RoutedEventHandler), typeof(TouchManager));    private static readonly RoutedEvent TapEvent = EventManager.RegisterRoutedEvent("Tap", RoutingStrategy.Direct, typeof(TapEventHandler), typeof(TouchManager));    private static readonly RoutedEvent TapAndHoldEvent = EventManager.RegisterRoutedEvent("TapAndHold", RoutingStrategy.Direct, typeof(TouchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent TapHoldAndReleaseEvent = EventManager.RegisterRoutedEvent("TapHoldAndRelease", RoutingStrategy.Direct, typeof(TouchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent TouchEnterEvent = EventManager.RegisterRoutedEvent("TouchEnter", RoutingStrategy.Direct, typeof(TouchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent TouchDownEvent = EventManager.RegisterRoutedEvent("TouchDown", RoutingStrategy.Direct, typeof(TouchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent TouchMoveEvent = EventManager.RegisterRoutedEvent("TouchMove", RoutingStrategy.Direct, typeof(TouchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent TouchUpEvent = EventManager.RegisterRoutedEvent("TouchUp", RoutingStrategy.Direct, typeof(TouchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent TouchLeaveEvent = EventManager.RegisterRoutedEvent("TouchLeave", RoutingStrategy.Direct, typeof(TouchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent LostTouchCaptureEvent = EventManager.RegisterRoutedEvent("LostTouchCapture", RoutingStrategy.Direct, typeof(TouchEventHandler), typeof(TouchManager));    private static readonly RoutedEvent TouchPulseEvent = EventManager.RegisterRoutedEvent("TouchPulse", RoutingStrategy.Bubble, typeof(TouchPulseEventHandler), typeof(TouchManager));    static TouchManager()    {        InitializeProperties();    }    private static bool isEnabled = true;    private static bool isTouchEnabled = true;    private static double touchMoveMinimumDistance = 1.0;    private static double dragStartDistance = 5.0;    private static double pinchStartDistance = 5.0;    private static double swipeStartDistance = 5.0;    private static double tapVicinity = 5.0;    private static int tapTime = 800;    private static int swipeInertiaDuration = 1000;    private static double multiTapDistance = 10.0;    private static int multiTapTime;    /// <summary>    /// Gets 捏合手势的优先级.    /// </summary>    internal static int PinchPriority => 100;    /// <summary>    /// Gets 拖拽手势的优先级.    /// </summary>    internal static int DragPriority => 200;    /// <summary>    /// Gets 滑动手势的优先级.    /// </summary>    internal static int SwipePriority => 300;    /// <summary>    /// Gets 点击手势的优先级.    /// </summary>    internal static int TapPriority => 400;    /// <summary>    /// Gets 拖拽手势的名称.    /// </summary>    internal static string DragGestureName => "DragGesture";    /// <summary>    /// Gets 捏合手势的名称.    /// </summary>    internal static string PinchGestureName => "PinchGesture";    /// <summary>    /// Gets 滑动手势的名称.    /// </summary>    internal static string SwipeGestureName => "SwipeGesture";    /// <summary>    /// Gets 惯性滑动手势的名称.    /// </summary>    internal static string SwipeInertiaGestureName => "SwipeInertiaGesture";    /// <summary>    /// Gets 待定点击手势的名称.    /// </summary>    internal static string TapPendingGestureName => "TapPending";    /// <summary>    /// Gets 点击手势的名称.    /// </summary>    internal static string TapGestureName => "TapGesture";    /// <summary>    /// Gets 点击并按住手势的名称.    /// </summary>    internal static string TapAndHoldGestureName => "TapAndHoldGesture";    /// <summary>    /// Gets 点击并抬起手势的名称.    /// </summary>    internal static string TapHoldAndReleaseGestureName => "TapHoldAndReleaseGesture";    /// <summary>    /// Gets or sets a value indicating whether 触控管理器是否启用.    /// </summary>    public static bool IsEnabled    {        get { return TouchManager.isEnabled; }        set { TouchManager.isEnabled = value; }    }    /// <summary>    /// Gets or sets a value indicating whether 系统触控功能是否启用.    /// </summary>    public static bool IsTouchEnabled    {        get { return TouchManager.isTouchEnabled; }        set { TouchManager.isTouchEnabled = value; }    }    /// <summary>    /// Gets or sets 拖拽开始的距离阈值.    /// </summary>    public static double DragStartDistance    {        get { return TouchManager.dragStartDistance; }        set { TouchManager.dragStartDistance = value; }    }    /// <summary>    /// Gets or sets 捏合开始的距离阈值.    /// </summary>    public static double PinchStartDistance    {        get { return TouchManager.pinchStartDistance; }        set { TouchManager.pinchStartDistance = value; }    }    /// <summary>    /// Gets or sets 滑动开始的距离阈值.    /// </summary>    public static double SwipeStartDistance    {        get { return TouchManager.swipeStartDistance; }        set { TouchManager.swipeStartDistance = value; }    }    /// <summary>    /// Gets or sets 滑动惯性的持续时间.    /// </summary>    public static int SwipeInertiaDuration    {        get { return TouchManager.swipeInertiaDuration; }        set { TouchManager.swipeInertiaDuration = value; }    }    /// <summary>    /// Gets or sets 点击判定的有效范围.    /// </summary>    public static double TapVicinity    {        get { return TouchManager.tapVicinity; }        set { TouchManager.tapVicinity = value; }    }    /// <summary>    /// Gets or sets 点击判定的超时时间.    /// </summary>    public static int TapTime    {        get { return TouchManager.tapTime; }        set { TouchManager.tapTime = value; }    }    /// <summary>    /// Gets or sets 多次点击判定的距离阈值.    /// </summary>    public static double MultiTapVicinity    {        get { return TouchManager.multiTapDistance; }        set { TouchManager.multiTapDistance = value; }    }    /// <summary>    /// Gets or sets 多次点击的时间阈值.    /// </summary>    public static int MultiTapTime    {        get { return TouchManager.multiTapTime; }        set { TouchManager.multiTapTime = value; }    }    /// <summary>    /// Gets 触发触控移动的最小距离.    /// </summary>    internal static double TouchMoveMinimumDistance => TouchManager.touchMoveMinimumDistance;    /// <summary>    /// 当请求停止手势识别时触发的内部事件.    /// </summary>    internal static event EventHandler<CeaseGesturesRequestedEventArgs>? CeaseGesturesRequested;    /// <summary>    /// 初始化触控相关的配置属性.    /// </summary>    private static void InitializeProperties()    {        multiTapTime = SafeNativeMethods.GetDoubleClickTime();    }    /// <summary>    /// 获取指定对象的拖拽启动触发器方式.    /// </summary>    /// <param name="dependencyObject">目标依赖对象.</param>    /// <returns>拖拽启动触发方式.</returns>    public static TouchDragStartTrigger GetDragStartTrigger(DependencyObject dependencyObject)    {        ArgumentNullException.ThrowIfNull(dependencyObject, nameof(dependencyObject));        return (TouchDragStartTrigger)dependencyObject.GetValue(TouchManager.DragStartTriggerProperty);    }    /// <summary>    /// 设置指定对象的拖拽启动触发器方式.    /// </summary>    /// <param name="dependencyObject">目标依赖对象.</param>    /// <param name="value">触发方式值.</param>    public static void SetDragStartTrigger(DependencyObject dependencyObject, TouchDragStartTrigger value)    {        ArgumentNullException.ThrowIfNull(dependencyObject, nameof(dependencyObject));        dependencyObject.SetValue(TouchManager.DragStartTriggerProperty, value);    }    /// <summary>    /// 获取滚动视图的滑动模式.    /// </summary>    /// <param name="dependencyObject">目标依赖对象.</param>    /// <returns>滑动模式枚举值.</returns>    public static ScrollViewerSwipeMode GetScrollViewerSwipeMode(DependencyObject dependencyObject)    {        ArgumentNullException.ThrowIfNull(dependencyObject, nameof(dependencyObject));        return (ScrollViewerSwipeMode)dependencyObject.GetValue(TouchManager.ScrollViewerSwipeModeProperty);    }    /// <summary>    /// 设置滚动视图的滑动模式.    /// </summary>    /// <param name="dependencyObject">目标依赖对象.</param>    /// <param name="value">滑动模式枚举值.</param>    public static void SetScrollViewerSwipeMode(DependencyObject dependencyObject, ScrollViewerSwipeMode value)    {        ArgumentNullException.ThrowIfNull(dependencyObject, nameof(dependencyObject));        dependencyObject.SetValue(TouchManager.ScrollViewerSwipeModeProperty, value);    }    /// <summary>    /// 获取是否应挂起鼠标提升.    /// </summary>    /// <param name="dependencyObject">目标依赖对象.</param>    /// <returns>如果应挂起则返回 true; 否则返回 false.</returns>    public static bool GetShouldSuspendMousePromotion(DependencyObject dependencyObject)    {        ArgumentNullException.ThrowIfNull(dependencyObject, nameof(dependencyObject));        return (bool)dependencyObject.GetValue(TouchManager.ShouldSuspendMousePromotionProperty);    }    /// <summary>    /// 设置是否应挂起鼠标提升.    /// </summary>    /// <param name="dependencyObject">目标依赖对象.</param>    /// <param name="value">指示是否挂起的布尔值.</param>    public static void SetShouldSuspendMousePromotion(DependencyObject dependencyObject, bool value)    {        ArgumentNullException.ThrowIfNull(dependencyObject, nameof(dependencyObject));        dependencyObject.SetValue(ShouldSuspendMousePromotionProperty, value);    }    /// <summary>    /// 响应拖拽启动触发器属性更改的回调.    /// </summary>    /// <param name="target">发生更改的对象.</param>    /// <param name="args">属性更改参数.</param>    private static void DragStartTriggerChanged(DependencyObject target, DependencyPropertyChangedEventArgs args)    {        TryGetTouchHelper(target)?.TryGetGestureHelper()?                                  .TryGetRecognizer<DragGestureRecognizer>()?                                  .OnDragStartTriggerChanged();    }    /// <summary>    /// 响应滚动视图滑动模式属性更改的回调.    /// </summary>    /// <param name="target">发生更改的对象.</param>    /// <param name="args">属性更改参数.</param>    private static void ScrollViewerSwipeModeChanged(DependencyObject target, DependencyPropertyChangedEventArgs args)    {        UIElement uiElement = (UIElement)target;        var helper = GetOrCreateTouchHelper(uiElement);        if (helper != null)        {            ScrollViewerSwipeMode mode = (ScrollViewerSwipeMode)args.NewValue;            if (helper.ScrollViewerHelper != null)            {                helper.ScrollViewerHelper.Dispose();                helper.ScrollViewerHelper = null;            }            switch (mode)            {                case ScrollViewerSwipeMode.Self:                    helper.ScrollViewerHelper = new ScrollViewerHelper((ScrollViewer)uiElement);                    break;                case ScrollViewerSwipeMode.Parent:                    helper.ScrollViewerHelper = new ParentScrollViewerHelper(uiElement);                    break;            }        }    }    /// <summary>    /// 响应是否挂起鼠标提升属性更改的回调.    /// </summary>    /// <param name="target">发生更改的对象.</param>    /// <param name="args">属性更改参数.</param>    private static void ShouldSuspendMousePromotionChanged(DependencyObject target, DependencyPropertyChangedEventArgs args)    {        UIElement uiElement = (UIElement)target;        bool shouldSuspend = (bool)args.NewValue;        MousePromotionSuspender.OnShouldSuspendMousePromotionChanged(uiElement, shouldSuspend);    }    /// <summary>    /// 添加拖拽开始事件处理程序.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <param name="handler">事件处理委托.</param>    /// <param name="handledEventsToo">是否处理已标记为已处理的事件.</param>    public static void AddDragStartedEventHandler(UIElement element, TouchEventHandler handler, bool handledEventsToo = false)    {        if (IsEnabled)        {            Verify(element, handler);            var recognizer = GestureManager.GetOrCreateGestureRecognizer<DragGestureRecognizer>(element);            if (recognizer != null)            {                recognizer.AddDragStartedHandler(handler);                element.AddHandler(DragStartedEvent, handler, handledEventsToo);            }        }    }    /// <summary>    /// 移除拖拽开始事件处理程序.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <param name="handler">事件处理委托.</param>    public static void RemoveDragStartedEventHandler(UIElement element, TouchEventHandler handler)    {        Verify(element, handler);        GestureManager.TryGetGestureRecognizer<DragGestureRecognizer>(element)?.RemoveDragStartedHandler(handler);        element.RemoveHandler(TouchManager.DragStartedEvent, handler);    }    /// <summary>    /// 添加拖拽事件处理程序.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <param name="handler">事件处理委托.</param>    /// <param name="handledEventsToo">是否处理已标记为已处理的事件.</param>    public static void AddDragEventHandler(UIElement element, TouchEventHandler handler, bool handledEventsToo = false)    {        if (IsEnabled)        {            Verify(element, handler);            var recognizer = GestureManager.GetOrCreateGestureRecognizer<DragGestureRecognizer>(element);            if (recognizer != null)            {                recognizer.AddDragHandler(handler);                element.AddHandler(DragEvent, handler, handledEventsToo);            }        }    }    /// <summary>    /// 移除拖拽事件处理程序.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <param name="handler">事件处理委托.</param>    public static void RemoveDragEventHandler(UIElement element, TouchEventHandler handler)    {        Verify(element, handler);        GestureManager.TryGetGestureRecognizer<DragGestureRecognizer>(element)?.RemoveDragHandler(handler);        element.RemoveHandler(DragEvent, handler);    }    /// <summary>    /// 添加拖拽完成事件处理程序.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <param name="handler">事件处理委托.</param>    /// <param name="handledEventsToo">是否处理已标记为已处理的事件.</param>    public static void AddDragFinishedEventHandler(UIElement element, TouchEventHandler handler, bool handledEventsToo = false)    {        if (IsEnabled)        {            Verify(element, handler);            var recognizer = GestureManager.GetOrCreateGestureRecognizer<DragGestureRecognizer>(element);            if (recognizer != null)            {                recognizer.AddDragFinishedHandler(handler);                element.AddHandler(DragFinishedEvent, handler, handledEventsToo);            }   