">目标对象.</param>    /// <param name="value">布尔值.</param>    [Obsolete("Obsoleted with 2016 Q1. Use TouchMode instead.", false)]    public static void SetIsTouchHitTestVisible(DependencyObject dependencyObject, bool value)    {        ArgumentNullException.ThrowIfNull(dependencyObject, nameof(dependencyObject));        dependencyObject.SetValue(TouchManager.IsTouchHitTestVisibleProperty, value);    }    /// <summary>    /// 获取实际触控命中测试是否可见.    /// </summary>    /// <param name="dependencyObject">目标对象.</param>    /// <returns>布尔值.</returns>    internal static bool GetActualIsTouchHitTestVisible(DependencyObject dependencyObject)    {        return (bool)dependencyObject.GetValue(TouchManager.ActualIsTouchHitTestVisibleProperty);    }    /// <summary>    /// 设置实际触控命中测试是否可见.    /// </summary>    /// <param name="dependencyObject">目标对象.</param>    /// <param name="value">布尔值.</param>    internal static void SetActualIsTouchHitTestVisible(DependencyObject dependencyObject, bool value)    {        dependencyObject.SetValue(TouchManager.ActualIsTouchHitTestVisibleProperty, value);    }    /// <summary>    /// 获取实际是否应抑制触控.    /// </summary>    /// <param name="dependencyObject">目标对象.</param>    /// <returns>布尔值.</returns>    internal static bool GetActualShouldSuppressTouch(DependencyObject dependencyObject)    {        return (bool)dependencyObject.GetValue(TouchManager.ActualShouldSuppressTouchProperty);    }    /// <summary>    /// 设置实际是否应抑制触控.    /// </summary>    /// <param name="dependencyObject">目标对象.</param>    /// <param name="value">布尔值.</param>    internal static void SetActualShouldSuppressTouch(DependencyObject dependencyObject, bool value)    {        dependencyObject.SetValue(TouchManager.ActualShouldSuppressTouchProperty, value);    }    /// <summary>    /// 响应触控模式更改的回调.    /// </summary>    private static void TouchModeChanged(DependencyObject target, DependencyPropertyChangedEventArgs args)    {        target.ClearValue(TouchManager.ActualIsTouchHitTestVisibleProperty);        target.ClearValue(TouchManager.ActualShouldSuppressTouchProperty);        switch ((TouchMode)args.NewValue)        {            case TouchMode.HitTestHidden:                TouchManager.SetActualIsTouchHitTestVisible(target, false);                break;            case TouchMode.None:                TouchManager.SetActualShouldSuppressTouch(target, true);                break;        }    }    /// <summary>    /// 响应实际命中测试可见性更改的回调.    /// </summary>    private static void ActualIsTouchHitTestVisibleChanged(DependencyObject target, DependencyPropertyChangedEventArgs args)    {        bool flag = (bool)args.NewValue;        TouchMode touchMode = TouchManager.GetTouchMode(target);        bool flag2 = touchMode == TouchMode.HitTestVisible || touchMode == TouchMode.Locked;        if (flag && !flag2)        {            TouchManager.SetActualIsTouchHitTestVisible(target, false);        }    }    /// <summary>    /// 响应实际抑制触控更改的回调.    /// </summary>    private static void ActualShouldSuppressTouchChanged(DependencyObject target, DependencyPropertyChangedEventArgs args)    {        bool flag = (bool)args.NewValue;        TouchMode touchMode = TouchManager.GetTouchMode(target);        if (touchMode == TouchMode.None && !flag)        {            TouchManager.SetActualShouldSuppressTouch(target, true);        }    }    /// <summary>    /// 响应命中测试可见性更改的回调.    /// </summary>    private static void IsTouchHitTestVisibleChanged(DependencyObject target, DependencyPropertyChangedEventArgs args)    {        if ((bool)args.NewValue)        {            TouchManager.SetTouchMode(target, TouchMode.HitTestVisible);        }        else        {            TouchManager.SetTouchMode(target, TouchMode.None);        }    }    /// <summary>    /// 处理锁定状态下的触控捕获.    /// </summary>    private static void HandleLockingTouch(UIElement element, TouchDevice touchDevice)    {        if (TouchManager.GetTouchMode(element) == TouchMode.Locked)        {            TouchManager.CaptureTouch(element, touchDevice);        }    }    /// <summary>    /// 处理锁定状态下的触控拦截.    /// </summary>    private static void HandleLockedTouch(UIElement element, RoutedEventArgs args)    {        if (!args.Handled && TouchManager.GetTouchMode(element) == TouchMode.Locked)        {            args.Handled = true;        }    }    /// <summary>    /// 请求停止指定根元素下的所有手势.    /// </summary>    /// <param name="root">根元素.</param>    public static void CeaseGestures(FrameworkElement root)    {        TouchManager.CeaseGesturesRequested?.Invoke(null, new CeaseGesturesRequestedEventArgs(root));    }    /// <summary>    /// 判断是否为触控输入.    /// </summary>    /// <param name="stylusDevice">笔设备.</param>    /// <param name="source">事件源.</param>    /// <param name="originalSource">原始源.</param>    /// <returns>如果是触控输入则返回 true.</returns>    internal static bool IsTouchInput(StylusDevice? stylusDevice, UIElement? source, UIElement? originalSource)    {        if (!TouchManager.IsTouchEnabled)        {            return false;        }        if (stylusDevice == null || stylusDevice.TabletDevice == null || stylusDevice.TabletDevice.Type != TabletDeviceType.Touch)        {            return false;        }        if (source == null || originalSource == null)        {            return false;        }        if (TouchManager.GetActualShouldSuppressTouch(originalSource) || !TouchManager.GetActualIsTouchHitTestVisible(source))        {            return false;        }        return true;    }    /// <summary>    /// 添加触控脉冲事件处理程序.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <param name="handler">处理委托.</param>    internal static void AddTouchPulseEventHandler(UIElement element, TouchPulseEventHandler handler)    {        Verify(element, handler);        element.AddHandler(TouchManager.TouchPulseEvent, handler);    }    /// <summary>    /// 移除触控脉冲事件处理程序.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <param name="handler">处理委托.</param>    internal static void RemoveTouchPulseEventHandler(UIElement element, TouchPulseEventHandler handler)    {        Verify(element, handler);        element.RemoveHandler(TouchManager.TouchPulseEvent, handler);    }    /// <summary>    /// 触发触控脉冲事件.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <param name="info">脉冲信息对象.</param>    internal static void RaiseTouchPulseEvent(UIElement element, object info)    {        TouchPulseEventArgs e = new TouchPulseEventArgs(TouchManager.TouchPulseEvent, info);        element.RaiseEvent(e);    }    /// <summary>    /// 获取或创建触控辅助对象.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <returns>辅助对象实例.</returns>    internal static TouchHelper? GetOrCreateTouchHelper(UIElement element)    {        if (!IsEnabled)        {            return null;        }        var helper = TryGetTouchHelper(element);        if (helper == null)        {            helper = new TouchHelper(element);            element.SetValue(TouchHelperProperty, helper);        }        return helper;    }    /// <summary>    /// 尝试获取触控辅助对象.    /// </summary>    /// <param name="obj">依赖对象.</param>    /// <returns>辅助对象实例.</returns>    internal static TouchHelper? TryGetTouchHelper(DependencyObject obj)    {        if (!IsEnabled)        {            return null;        }        return (TouchHelper)obj.GetValue(TouchHelperProperty);    }    /// <summary>    /// 获取触控设备实例.    /// </summary>    /// <param name="touchEventArgs">触控参数.</param>    /// <param name="lostTouchCaptureArgs">丢失捕获参数.</param>    /// <param name="lastTouchMoveArgs">最后移动参数.</param>    /// <returns>设备实例.</returns>    internal static TouchDevice? GetTouchDevice(TouchEventArgs? touchEventArgs, TouchEventArgs? lostTouchCaptureArgs, 