lper helper)    {        bool flag = helper.TouchEnterHandlers.Count + helper.TouchDownHandlers.Count + helper.TouchMoveHandlers.Count + helper.TouchUpHandlers.Count + helper.TouchLeaveHandlers.Count + helper.LostTouchCaptureHandlers.Count > 0;        if (!helper.IsTouchSubscriptionEstablished && flag)        {            helper.IsTouchSubscriptionEstablished = true;            element.TouchEnter += TouchManager.OnTouchEnter;            element.TouchDown += TouchManager.OnTouchDown;            element.TouchMove += TouchMoveUtilities.OnTouchMove;            element.TouchUp += TouchManager.OnTouchUp;            element.TouchLeave += TouchManager.OnTouchLeave;            element.LostTouchCapture += TouchManager.OnLostTouchCapture;            TouchManager.DisableFlicksAndPressAndHold(element);        }        else if (helper.IsTouchSubscriptionEstablished && !flag)        {            helper.IsTouchSubscriptionEstablished = false;            element.TouchEnter -= TouchManager.OnTouchEnter;            element.TouchDown -= TouchManager.OnTouchDown;            element.TouchMove -= TouchMoveUtilities.OnTouchMove;            element.TouchUp -= TouchManager.OnTouchUp;            element.TouchLeave -= TouchManager.OnTouchLeave;            element.LostTouchCapture -= TouchManager.OnLostTouchCapture;            TouchMoveUtilities.ClearTouchMoveHelper(element);        }    }    /// <summary>    /// 禁用干扰手势.    /// </summary>    /// <param name="element">元素.</param>    internal static void DisableFlicksAndPressAndHold(UIElement element)    {        Stylus.SetIsPressAndHoldEnabled(element, false);        Stylus.SetIsFlicksEnabled(element, false);    }    /// <summary>    /// 触发进入事件.    /// </summary>    /// <param name="element">元素.</param>    internal static void RaiseTouchEnterEvent(UIElement element, System.Windows.Input.TouchEventArgs originalArgs)    {        TouchEventArgs e = new TouchEventArgs(TouchManager.TouchEnterEvent, originalArgs, element);        element.RaiseEvent(e);        originalArgs.Handled = e.Handled;        TouchManager.MarkLastEventTouchInput(element);    }    /// <summary>    /// 触发按下事件.    /// </summary>    /// <param name="element">元素.</param>    internal static void RaiseTouchDownEvent(UIElement element, System.Windows.Input.TouchEventArgs originalArgs, object originalSource)    {        var e = new TouchEventArgs(TouchDownEvent, originalArgs, originalSource);        element.RaiseEvent(e);        originalArgs.Handled = e.Handled;        HandleLockingTouch(element, e.TouchDevice);        HandleLockedTouch(element, originalArgs);        MarkLastEventTouchInput(element);    }    /// <summary>    /// 触发移动事件.    /// </summary>    /// <param name="element">元素.</param>    internal static void RaiseTouchMoveEvent(UIElement element, System.Windows.Input.TouchEventArgs originalArgs, object originalSource, bool shouldHandleOriginalArgs)    {        var e = new TouchEventArgs(TouchMoveEvent, originalArgs, originalSource);        element.RaiseEvent(e);        if (shouldHandleOriginalArgs) { originalArgs.Handled = e.Handled; }        HandleLockedTouch(element, originalArgs);        MarkLastEventTouchInput(element);    }    /// <summary>    /// 触发抬起事件.    /// </summary>    /// <param name="element">元素.</param>    internal static void RaiseTouchUpEvent(UIElement element, System.Windows.Input.TouchEventArgs originalArgs, object originalSource)    {        var e = new TouchEventArgs(TouchUpEvent, originalArgs, originalSource);        element.RaiseEvent(e);        originalArgs.Handled = e.Handled;        HandleLockedTouch(element, originalArgs);        MarkLastEventTouchInput(element);    }    /// <summary>    /// 触发离开事件.    /// </summary>    /// <param name="element">元素.</param>    internal static void RaiseTouchLeaveEvent(UIElement element, System.Windows.Input.TouchEventArgs originalArgs)    {        TouchEventArgs e = new TouchEventArgs(TouchManager.TouchLeaveEvent, originalArgs, element);        element.RaiseEvent(e);        originalArgs.Handled = e.Handled;        TouchManager.MarkLastEventTouchInput(element);    }    /// <summary>    /// 获取原始源.    /// </summary>    /// <param name="element">元素.</param>    internal static DependencyObject GetOriginalSource(DependencyObject element)    {        if (GetActualIsTouchHitTestVisible(element))        {            return element;        }        return element.GetParents().First(el => GetActualIsTouchHitTestVisible(el));    }    /// <summary>    /// 验证触控合法性.    /// </summary>    /// <param name="element">元素.</param>    internal static bool IsValidTouchInput(UIElement element, object originalSource)    {        if (!TouchManager.IsTouchEnabled)        {            return false;        }        if (originalSource is DependencyObject obj && TouchManager.GetActualShouldSuppressTouch(obj))        {            return false;        }        if (!TouchManager.GetActualIsTouchHitTestVisible(element))        {            return false;        }        return true;    }    private static void OnTouchEnter(object? sender, System.Windows.Input.TouchEventArgs args)    {        if (sender is UIElement element)        {            if (IsValidTouchInput(element, args.OriginalSource))            {                RaiseTouchEnterEvent(element, args);            }        }    }    private static void OnTouchDown(object? sender, System.Windows.Input.TouchEventArgs args)    {        if (sender is UIElement element)        {            if (IsValidTouchInput(element, args.OriginalSource))            {                var touchPoint = args.GetTouchPoint(element);                int id = touchPoint.TouchDevice.Id;                Point position = touchPoint.Position;                var moveHelper = TouchMoveUtilities.GetOrCreateTouchMoveHelper(element);                moveHelper.OnTouchDown(id, position);                var originalSource = GetOriginalSource((DependencyObject)args.OriginalSource);                RaiseTouchDownEvent(element, args, originalSource);            }        }    }    private static void OnTouchUp(object? sender, System.Windows.Input.TouchEventArgs args)    {        if (sender is UIElement element)        {            if (IsValidTouchInput(element, args.OriginalSource))            {                var touchPoint = args.GetTouchPoint(element);                int id = touchPoint.TouchDevice.Id;                Point position = touchPoint.Position;                var moveHelper = TouchMoveUtilities.GetOrCreateTouchMoveHelper(element);                var originalSource = GetOriginalSource((DependencyObject)args.OriginalSource);                if (moveHelper.ShouldRaiseLastTouchMoveBeforeTouchUp(id, position))                {                    TouchManager.RaiseTouchMoveEvent(element, args, originalSource, false);                }                RaiseTouchUpEvent(element, args, originalSource);                moveHelper.OnTouchUp(id);            }        }    }    private static void OnTouchLeave(object? sender, System.Windows.Input.TouchEventArgs args)    {        if (sender is UIElement element)        {            if (IsValidTouchInput(element, args.OriginalSource))            {                RaiseTouchLeaveEvent(element, args);            }        }    }    private static void OnLostTouchCapture(object? sender, System.Windows.Input.TouchEventArgs args)    {        if (sender is UIElement element)        {            if (IsValidTouchInput(element, args.OriginalSource))            {                var e = new TouchEventArgs(TouchManager.LostTouchCaptureEvent, args, element);                element.RaiseEvent(e);                args.Handled = e.Handled;            }        }    }    private static void MarkLastEventTouchInput(UIElement element)    {        var helper = TouchManager.GetOrCreateTouchHelper(element);        if (helper != null)        {            helper.SuspendMouseMovesCount = 2;        }    }}